import theme from '../theme'

const Title = () => (
    <div>
      <h1 className="title">When you wake</h1>
      <div className="sub-title">Portfolio website of Jithin KS</div>
    </div>
  );

const style = `
.title {
  font-size:40px;
  display: inline-block;
  margin:0;
  color: ${theme.titleColor}
}
`

export default Title
